{
  "title": "Introduction to Python for Game Development",
  "description": "This course is designed for beginners who want to learn Python with a focus on game development. It covers the basics of Python programming and introduces key concepts and libraries used in creating games.",
  "modules": [
    {
      "id": "module1",
      "title": "Getting Started with Python",
      "description": "Learn the fundamentals of Python programming, including installation, syntax, data types, and basic control structures."
    },
    {
      "id": "module2",
      "title": "Object-Oriented Programming in Python",
      "description": "Explore the principles of object-oriented programming (OOP) in Python, including classes, objects, inheritance, and encapsulation, which are essential for game development."
    },
    {
      "id": "module3",
      "title": "Introduction to Game Development Concepts",
      "description": "Understand the basic concepts of game development, including game loops, event handling, and graphics rendering, as well as an introduction to the Pygame library."
    },
    {
      "id": "module4",
      "title": "Building Your First Game",
      "description": "Apply your knowledge by creating a simple game using Python and Pygame. This module will guide you through the process of designing, coding, and testing your game."
    }
  ]
}
